--查看战报
function LxArenaHandler:OnArenaRecordsResp(pb)
    ModuleCenter.Arena:SetRecords(pb)
    FireEvent(EventNames.REFRESH_ARENA_REPORTLIST)
end
--领取累计挑战奖励
function LxArenaHandler:OnArenaChallengeCountRewardResp(pb)
    ModuleCenter.Arena:SetChallengeReward(pb)
    FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.CrestGame, pb.rewardInfo)
    FireEvent(EventNames.REFRESH_ARENA_BOX)
end
--手动刷新挑战列表
function LxArenaHandler:OnArenaRefreshResp(pb)
    ModuleCenter.Arena:SetArenaChallenge(pb)
    FireEvent(EventNames.REFRESH_ARENA_CHALLENGELIST)
    CtrlCenter.City:RefreshArenaIconInfo()
end
--挑战列表
function LxArenaHandler:OnArenaChallengeListResp(pb)
    ModuleCenter.Arena:SetArenaChallenge(pb)
    FireEvent(EventNames.REFRESH_ARENA_CHALLENGELIST)
    CtrlCenter.City:RefreshArenaIconInfo()
end

return LxArenaHandler